framework_css:
:root {
    /* Color palette */
    --color-background: #FFFFFF;
    --color-border: #C0C0C0;
    --color-border-subtle: #F5F5F5;
    --color-text: #000000;
    --color-link: #0000EE;
    --color-link-visited: #551A8B;

    /* Typography */
    --font-family-heading: Arial, Verdana, Helvetica, sans-serif;
    --font-family-body: Arial, Tahoma, Helvetica, sans-serif;
    --font-family-code: "Source Code Pro", monospace;

    --font-size-h1: 18px;
    --font-size-h2: 16px;
    --font-size-h3: 14px;
    --font-size-body: 14px;
    --font-size-small: 12px;

    --font-weight-regular: 400;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.4;
    --line-height-relaxed: 1.6;

    /* Spacing scale (multiples of 4px) */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 12px;
    --space-4: 16px;
    --space-5: 24px;
    --space-6: 32px;
}

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    margin: 8px; /* matches classic browser default margin */
    background-color: var(--color-background);
    color: var(--color-text);
    font-family: var(--font-family-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
}

a {
    color: var(--color-link);
    text-decoration: underline;
}

a:visited {
    color: var(--color-link-visited);
}

a:hover,
a:focus {
    text-decoration: underline;
}

h1,
h2,
h3 {
    font-family: var(--font-family-heading);
    font-weight: var(--font-weight-bold);
    margin: 0;
}

h1.site-title {
    font-size: var(--font-size-h1);
    line-height: var(--line-height-tight);
}

#page {
    /* no max-width to mimic full-width old forum layout */
}

/* Header */

.site-header {
    margin-bottom: var(--space-2);
}

.site-header__title-row {
    margin-bottom: var(--space-1);
}

.site-header__nav-bar {
    border: 1px solid var(--color-border);
    padding: var(--space-1) var(--space-2);
    background-color: var(--color-background);
}

.main-nav {
    list-style: none;
    margin: 0;
    padding: 0;
}

.main-nav__item {
    display: inline;
    margin-right: var(--space-3);
    white-space: nowrap;
}

.main-nav__item:last-child {
    margin-right: 0;
}

/* Main content area */

.site-content {
    margin-top: var(--space-2);
}

.content-box {
    border: 1px solid var(--color-border);
    padding: var(--space-2);
    background-color: var(--color-background);
    min-height: 200px; /* simple scaffold for page content */
}

/* Footer */

.site-footer {
    margin-top: var(--space-4);
    padding-top: var(--space-2);
    border-top: 1px solid var(--color-border);
    font-size: var(--font-size-small);
}

.footer-nav__list {
    list-style: none;
    margin: 0 0 var(--space-1) 0;
    padding: 0;
}

.footer-nav__item {
    display: inline;
    margin-right: var(--space-2);
}

.footer-nav__item::after {
    content: "|";
    margin-left: var(--space-2);
}

.footer-nav__item:last-child {
    margin-right: 0;
}

.footer-nav__item:last-child::after {
    content: "";
    margin: 0;
}

.footer-meta {
    margin: 0;
}

.footer-year {
    /* keeps year visually inline but easy to update via script if needed */
}
